	virtual int rtti() const override;

	/// Set the bar titles
	void setBarTitles( const QList< QwtText >& );
	/// Get the bar titles
	QList< QwtText > barTitles() const;

	/// Set samples from a vector of QwtSetSample
	void setSamples( const QVector< QwtSetSample >& );
