	void addAxisAlignment(const QList< QwtPlot* >& plots, int axisId);
	// 移除指定的轴对齐配置
	bool removeAxisAlignment(const QList< QwtPlot* >& plots, int axisId);
	// 清除所有轴对齐配置
	void clearAxisAlignment();
	// 应用所有轴对齐配置，对记录的plot和轴进行对齐
